// Фиксированная дата для теста (или вчера)
const dateStr = '2026-02-17';
const dateFromRfc = dateStr + 'T00:00:00%2B03:00';
const dateToRfc = dateStr + 'T23:59:59%2B03:00';
return [{ json: { date_from_rfc: dateFromRfc, date_to_rfc: dateToRfc, date: dateStr } }];

// Запрос к WB Statistics API — возвращаем RAW ответ для проверки
// Замените TOKEN на свой токен категории Статистика
const dates = $('Code — Дата').first().json;
const TOKEN = 'WB_API_TOKEN_PLACEHOLDER';
const url = `https://statistics-api.wildberries.ru/api/v5/supplier/reportDetailByPeriod?dateFrom=${dates.date_from_rfc}&dateTo=${dates.date_to_rfc}&period=daily&rrdid=0&limit=100000`;

try {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: { Authorization: TOKEN },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
  const bodyStr = typeof res.body === 'string' ? res.body : (res.body ? JSON.stringify(res.body) : '');
  return [{
    json: {
      statusCode: res.statusCode,
      bodyLength: bodyStr.length,
      bodyPreview: bodyStr.length > 500 ? bodyStr.slice(0, 500) + '...' : bodyStr,
      bodyEmpty: bodyStr.length === 0,
      contentType: res.headers?.['content-type'] || '',
      date: dates.date
    }
  }];
} catch (e) {
  return [{ json: { error: e.message, date: dates.date } }];
}
